CREATE TYPE "UserRole" AS ENUM ('learner', 'editor', 'admin');
CREATE TYPE "OneTimeTokenPurpose" AS ENUM ('email_verification', 'password_reset');
CREATE TYPE "RequestStatus" AS ENUM ('pending', 'processing', 'completed', 'cancelled');
CREATE TABLE "users" ("id" UUID NOT NULL, "email" VARCHAR(320) NOT NULL, "password_hash" TEXT NOT NULL, "email_verified_at" TIMESTAMP(3), "role" "UserRole" NOT NULL DEFAULT 'learner', "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "users_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "users_email_key" ON "users"("email");
CREATE TABLE "user_profiles" ("user_id" UUID NOT NULL, "display_name" VARCHAR(100), "interface_locale" VARCHAR(10) NOT NULL DEFAULT 'pl', "notifications_enabled" BOOLEAN NOT NULL DEFAULT false, "onboarding_completed_at" TIMESTAMP(3), CONSTRAINT "user_profiles_pkey" PRIMARY KEY ("user_id"));
CREATE TABLE "user_courses" ("id" UUID NOT NULL, "user_id" UUID NOT NULL, "language" VARCHAR(10) NOT NULL, "learning_goal" VARCHAR(50) NOT NULL, "daily_minutes" INTEGER NOT NULL DEFAULT 15, "thai_transliteration_enabled" BOOLEAN NOT NULL DEFAULT true, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "user_courses_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "user_courses_user_id_language_key" ON "user_courses"("user_id", "language");
CREATE TABLE "refresh_tokens" ("id" UUID NOT NULL, "user_id" UUID NOT NULL, "family_id" UUID NOT NULL, "token_hash" VARCHAR(128) NOT NULL, "expires_at" TIMESTAMP(3) NOT NULL, "revoked_at" TIMESTAMP(3), "replaced_by_id" UUID, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "refresh_tokens_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "refresh_tokens_token_hash_key" ON "refresh_tokens"("token_hash"); CREATE UNIQUE INDEX "refresh_tokens_replaced_by_id_key" ON "refresh_tokens"("replaced_by_id"); CREATE INDEX "refresh_tokens_user_id_family_id_idx" ON "refresh_tokens"("user_id", "family_id");
CREATE TABLE "one_time_tokens" ("id" UUID NOT NULL, "user_id" UUID NOT NULL, "purpose" "OneTimeTokenPurpose" NOT NULL, "token_hash" VARCHAR(128) NOT NULL, "expires_at" TIMESTAMP(3) NOT NULL, "used_at" TIMESTAMP(3), CONSTRAINT "one_time_tokens_pkey" PRIMARY KEY ("id")); CREATE UNIQUE INDEX "one_time_tokens_token_hash_key" ON "one_time_tokens"("token_hash");
CREATE TABLE "consents" ("id" UUID NOT NULL, "user_id" UUID NOT NULL, "key" VARCHAR(80) NOT NULL, "granted" BOOLEAN NOT NULL, "version" VARCHAR(30) NOT NULL, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "consents_pkey" PRIMARY KEY ("id")); CREATE INDEX "consents_user_id_key_idx" ON "consents"("user_id", "key");
CREATE TABLE "data_export_requests" ("id" UUID NOT NULL, "user_id" UUID NOT NULL, "status" "RequestStatus" NOT NULL DEFAULT 'pending', "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "data_export_requests_pkey" PRIMARY KEY ("id"));
CREATE TABLE "account_deletion_requests" ("id" UUID NOT NULL, "user_id" UUID NOT NULL, "status" "RequestStatus" NOT NULL DEFAULT 'pending', "scheduled_for" TIMESTAMP(3) NOT NULL, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "account_deletion_requests_pkey" PRIMARY KEY ("id"));
CREATE TABLE "audit_logs" ("id" UUID NOT NULL, "user_id" UUID, "event" VARCHAR(100) NOT NULL, "ip_hash" VARCHAR(128), "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "audit_logs_pkey" PRIMARY KEY ("id")); CREATE INDEX "audit_logs_user_id_event_idx" ON "audit_logs"("user_id", "event");
ALTER TABLE "user_profiles" ADD CONSTRAINT "user_profiles_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "user_courses" ADD CONSTRAINT "user_courses_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "refresh_tokens" ADD CONSTRAINT "refresh_tokens_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "one_time_tokens" ADD CONSTRAINT "one_time_tokens_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "consents" ADD CONSTRAINT "consents_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "data_export_requests" ADD CONSTRAINT "data_export_requests_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "account_deletion_requests" ADD CONSTRAINT "account_deletion_requests_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "audit_logs" ADD CONSTRAINT "audit_logs_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE SET NULL ON UPDATE CASCADE;
